import urllib.request, urllib.error
base='http://localhost:5000'
paths=['/success','/done','/solve','/winner','/complete','/xss_success','/xss1','/xss11','/xss/solve','/triangle_success','/submit_flag','/getflag','/get-flag','/flag.txt','/static/flag.txt','/static/flag','/.flag','/static/.flag','/secret','/hidden','/admin/flag','/api/submit','/api/solve']
for p in paths:
    url=base+p
    try:
        with urllib.request.urlopen(url, timeout=5) as resp:
            print(p, resp.getcode(), resp.getheader('Content-Type'))
    except urllib.error.HTTPError as e:
        print(p, e.code)
    except Exception as e:
        print(p, 'ERR', e)

